patch:
--- a/counter.v
+++ b/counter.v
@@ -1,13 +1,13 @@
 module counter16 (
   input clk,
   input rst_n,
   input enable,
   output [15:0] count
 );
   reg [15:0] counter;
   always @(posedge clk or negedge rst_n)
     if (!rst_n) counter <= 0;
     else if (enable) counter <= counter + 1;
   assign count = counter;
 endmodule

 module top;
   wire clock, reset, en;
   wire [15:0] cnt;
-  counter16 inst (.clk(clock), .enable(en), .count(cnt));
+  counter16 inst (.clk(clock), .rst_n(reset), .enable(en), .count(cnt));
 endmodule

